11	const BYTES_PER_KB = 1024;
12	const BYTES_PER_MB = BYTES_PER_KB * BYTES_PER_KB;
13	const MAX_BODY_SIZE = BYTES_PER_MB;
14	const MAX_RESPONSE_SIZE = 50 * BYTES_PER_MB;
15	const CLP_HEADER_PREFIX = "x-clp-";
16	const GATEWAY_HEADER = "x-clp-gateway";
17	const HTTP_FORBIDDEN = 403;
18	const HTTP_RATE_LIMITED = 429;
19	const HTTP_PAYLOAD_TOO_LARGE = 413;
20	const HTTP_REQUEST_TIMEOUT = 408;
21	const RATE_LIMIT_WINDOW_MS = 60_000;
22	const RATE_LIMIT_MAX_HITS = 100;
23	const SERVER_REQUEST_TIMEOUT_MS = 120_000;
24	const MS_PER_SECOND = 1000;
