67	/** Simple in-memory rate limiter */
68	class RateLimiter {
69	    private hits = new Map<string, {count: number; resetAt: number}>();
70	
71	    private maxHits: number;
72	
73	    private windowMs: number;
74	
75	    constructor (maxHits: number, windowMs: number) {
76	        this.maxHits = maxHits;
77	        this.windowMs = windowMs;
78	    }
79	
80	    check (ip: string): {allowed: boolean; remaining: number; resetAt: number} {
81	        const now = Date.now();
82	        let entry = this.hits.get(ip);
83	        if (!entry || now >= entry.resetAt) {
84	            entry = {count: 0, resetAt: now + this.windowMs};
85	            this.hits.set(ip, entry);
86	        }
87	        entry.count++;
88	        const allowed = entry.count <= this.maxHits;
89	        return {allowed: allowed, remaining: Math.max(0, this.maxHits - entry.count), resetAt: entry.resetAt};
90	    }
91	}
