101	// NFR-12: Reject X-CLP-* headers from untrusted sources (spoofing prevention)
102	// In production: without a gateway, any x-clp-* header is spoofed → reject.
103	// With a gateway, only x-clp-role is trusted; other x-clp-* headers are suspicious → reject.
104	// Gateway marker is preserved here for NFR-11 to check, then deleted in NFR-11 after RBAC.
105	    .use("/api/*", async (c, next) => {
106	        if (isProduction()) {
107	            const hasGatewayHeader = Boolean(c.req.header(GATEWAY_HEADER));
108	            for (const [key] of c.req.raw.headers.entries()) {
109	                if (key.startsWith(CLP_HEADER_PREFIX) && key !== GATEWAY_HEADER) {
110	                    if (!hasGatewayHeader) {
111	                        c.status(HTTP_FORBIDDEN);
112	
113	                        return c.json({error: `Rejected spoofed header: ${key}`});
114	                    } else if (key !== "x-clp-role") {
115	                        // Gateway present but non-role x-clp-* header is suspicious
116	                        c.status(HTTP_FORBIDDEN);
117	
118	                        return c.json({error: `Rejected spoofed header: ${key}`});
119	                    }
120	                }
121	            }
122	        }
123	
124	        return next();
125	    })
