127	// NFR-11: RBAC enforcement in production mode when a gateway is present.
128	// The gateway is responsible for setting x-clp-role based on authenticated user
129	// permissions. Without a gateway, requests are direct from trusted clients and
130	// all operations are permitted.
131	    .use("/api/*", async (c, next) => {
132	        if (!isProduction()) {
133	            return next();
134	        }
135	        const hasGateway = Boolean(c.req.header(GATEWAY_HEADER));
136	        if (!hasGateway) {
137	            return next();
138	        }
139	        const role = getRole(c);
140	        const {method} = c.req;
141	
142	        // Write operations require editor role; read operations allow viewer
143	        if (WRITE_METHODS.has(method) && !hasRole(role, "editor")) {
144	            c.status(HTTP_FORBIDDEN);
145	
146	            return c.json({error: "Insufficient permissions for this operation"});
147	        }
148	
149	        // Strip gateway marker so downstream can't re-use it
150	        c.req.raw.headers.delete(GATEWAY_HEADER);
151	
152	        return next();
153	    })
