155	        const ip = c.req.raw.headers.get("x-forwarded-for")?.split(",")[0]?.trim() ?? c.req.raw.headers.get("x-real-ip") ?? "unknown";
156	        const {allowed, remaining, resetAt} = dashboardLimiter.check(ip);
157	        c.header("X-RateLimit-Remaining", String(remaining));
158	        c.header("X-RateLimit-Reset", String(Math.ceil(resetAt / MS_PER_SECOND)));
159	        if (!allowed) {
