178	// NFR: Request timeout — prevents long-running queries from blocking the server
179	    .use("/api/*", async (c, next) => {
180	        const controller = new AbortController();
181	        const timeout = setTimeout(() => {
182	            controller.abort();
183	        }, SERVER_REQUEST_TIMEOUT_MS);
184	
185	        c.req.raw.signal.addEventListener("abort", () => {
186	            controller.abort();
187	        });
188	
189	        try {
190	            await Promise.race([
191	                next(),
192	                new Promise((resolve) => {
193	                    controller.signal.addEventListener("abort", () => {
194	                        resolve(null);
195	                    });
196	                }),
197	            ]);
198	        } finally {
199	            clearTimeout(timeout);
200	        }
201	
202	        if (controller.signal.aborted && !c.req.raw.signal.aborted) {
203	            c.status(HTTP_REQUEST_TIMEOUT);
204	
205	            return c.json({error: "Request timed out"});
206	        }
207	
208	        return c.body(null);
