226	async function executeDatasourceQuery (
227	    dsType: string,
228	    body: {queries: {refId: string; query: unknown; [key: string]: unknown}[]; range: {from: number; to: number}},
229	): Promise<{data: unknown[]; errors?: {message: string; refId?: string}[]}> {
230	    const {queries} = body;
231	    const errors: {message: string; refId?: string}[] = [];
232	    const allData: unknown[] = [];
233	
234	    for (const query of queries) {
235	        try {
236	            switch (dsType) {
237	                case "mysql": {
238	                    const sql = String(query.query);
239	                    const safety = validateSqlSafety(sql);
240	                    if (!safety.safe) {
241	                        errors.push({message: safety.reason ?? "Unsafe SQL", refId: query.refId});
242	                        break;
243	                    }
244	                    const limit = getApplicableRowLimit(sql);
245	                    const limitedSql = injectLimit(sql, limit);
246	                    // eslint-disable-next-line dot-notation
247	                    const params = Array.isArray(query["params"]) ?
248	                        query["params"] as unknown[] :
249	                        undefined;
250	                    const rows = await executeMySQLQuery(limitedSql, undefined, params);
251	                    const frame = rowsToDataFrame(rows, query.refId, limit);
252	                    allData.push(frame);
253	                    break;
254	                }
255	                case "clp": {
256	                    // CLP queries use SSE streaming internally; for the non-streaming endpoint,
257	                    // we run the streaming executor and collect all partial results
258	                    const collectedData: unknown[] = [];
259	                    await executeClpQueryStreaming(
260	                        {
261	                            queryString: String(query.query),
262	                            datasets: Array.isArray(query["datasets"]) ?
263	                                query["datasets"] as string[] :
264	                                [],
265	                            ignoreCase: Boolean(query["ignoreCase"]),
266	                            timeRange: body.range,
267	                            queryType: "search",
268	                            refId: query.refId,
269	                        },
270	                        {
271	                            onPartial: async (partial) => {
272	                                collectedData.push(...partial.data);
273	                            },
274	                        },
275	                    );
276	                    allData.push(...collectedData);
277	                    break;
278	                }
279	                case "infinity": {
280	                    const infinityQuery = buildInfinityQuery(query);
281	                    const result = await executeInfinityQuery(infinityQuery, infinityAllowedHosts);
282	                    if (result.error) {
283	                        errors.push({message: result.error, refId: query.refId});
284	                    } else {
285	                        allData.push(...result.data);
286	                    }
287	                    break;
288	                }
289	                default:
290	                    errors.push({message: `Unknown datasource type: ${dsType}`, refId: query.refId});
291	            }
292	        } catch (error) {
293	            const message = error instanceof Error ?
294	                error.message :
295	                "Query execution failed";
296	
297	            errors.push({message, refId: query.refId});
298	        }
299	    }
300	
301	    return {data: allData,
302	        ...(0 < errors.length ?
303	            {errors} :
304	            {})};
305	}
