317	async function executeDatasourceQueryStreaming (
318	    dsType: string,
319	    body: {queries: {refId: string; query: unknown; [key: string]: unknown}[]; range: {from: number; to: number}},
320	    onPartial: (result: {data: unknown[]; errors?: {message: string; refId?: string}[]}) => Promise<void>,
321	): Promise<{data: unknown[]; errors?: {message: string; refId?: string}[]}> {
322	    const {queries} = body;
323	    const errors: {message: string; refId?: string}[] = [];
324	    const allData: unknown[] = [];
325	
326	    for (const query of queries) {
327	        try {
328	            let queryData: unknown[] = [];
329	            switch (dsType) {
330	                case "mysql": {
331	                    const sql = String(query.query);
332	                    const safety = validateSqlSafety(sql);
333	                    if (!safety.safe) {
334	                        errors.push({message: safety.reason ?? "Unsafe SQL", refId: query.refId});
335	                        break;
336	                    }
337	                    const limit = getApplicableRowLimit(sql);
338	                    const limitedSql = injectLimit(sql, limit);
339	                    // eslint-disable-next-line dot-notation
340	                    const params = Array.isArray(query["params"]) ?
341	                        query["params"] as unknown[] :
342	                        undefined;
343	                    let totalRows = 0;
344	                    await executeMySQLQueryStream(limitedSql, async (rows) => {
345	                        totalRows += rows.length;
346	                        const frame = rowsToDataFrame(rows, query.refId, limit);
347	                        await onPartial({data: [frame]});
348	                    }, undefined, params);
349	                    // Final aggregated frame for the complete result
350	                    queryData = [{name: query.refId, fields: [], length: totalRows}];
351	                    break;
352	                }
353	                case "clp": {
354	                    const result = await executeClpQueryStreaming(
355	                        {
356	                            queryString: String(query.query),
357	                            datasets: Array.isArray(query["datasets"]) ?
358	                                query["datasets"] as string[] :
359	                                [],
360	                            ignoreCase: Boolean(query["ignoreCase"]),
361	                            timeRange: body.range,
362	                            queryType: "search",
363	                            refId: query.refId,
364	                        },
365	                        {
366	                            onPartial,
367	                        },
368	                    );
369	                    queryData = result.data;
370	                    break;
371	                }
372	                case "infinity": {
373	                    const infinityQuery = buildInfinityQuery(query);
374	                    const result = await executeInfinityQuery(infinityQuery, infinityAllowedHosts);
375	                    if (result.error) {
376	                        errors.push({message: result.error, refId: query.refId});
377	                    } else {
378	                        queryData = result.data;
379	                    }
380	                    break;
381	                }
382	                default:
383	                    errors.push({message: `Unknown datasource type: ${dsType}`, refId: query.refId});
384	            }
385	
386	            allData.push(...queryData);
387	            if (0 < queryData.length) {
388	                await onPartial({data: queryData});
389	            }
390	        } catch (error) {
391	            const message = error instanceof Error ?
392	                error.message :
393	                "Query execution failed";
394	
395	            errors.push({message, refId: query.refId});
396	            await onPartial({data: [], errors: [{message: message, refId: query.refId}]});
397	        }
398	    }
399	
400	    return {data: allData,
401	        ...(0 < errors.length ?
402	            {errors} :
403	            {})};
404	}
