460	/**
461	 *
462	 * @param sql
463	 * @param onBatch
464	 * @param timeoutMs
465	 * @param params
466	 */
467	async function executeMySQLQueryStream (
468	    sql: string,
469	    onBatch: (rows: Record<string, unknown>[]) => Promise<void>,
470	    timeoutMs: number = QUERY_TIMEOUTS.MYSQL_QUERY_TIMEOUT_MS,
471	    params?: unknown[],
472	): Promise<void> {
473	    const {SqlDbHost: host, SqlDbPort: port, SqlDbName: database} = settings;
474	    // eslint-disable-next-line dot-notation
475	    const user = process.env["CLP_DB_USER"] ?? "clp-user";
476	    // eslint-disable-next-line dot-notation
477	    const password = process.env["CLP_DB_PASS"] ?? "";
478	
479	    // Use callback-based mysql2 for streaming support (query().stream())
480	    const mysqlCb = await import("mysql2");
481	    const connection = mysqlCb.createConnection({host, port, user, password, database});
482	
483	    const timeoutId = setTimeout(() => {
484	        connection.destroy();
485	    }, timeoutMs);
486	
487	    try {
488	        // Set read-only mode for safety
489	        await new Promise<void>((resolve, reject) => {
490	            connection.query("SET TRANSACTION READ ONLY", (err: unknown) => {
491	                if (err) { reject(err); } else { resolve(); }
492	            });
493	        });
494	        await new Promise<void>((resolve, reject) => {
495	            connection.query("START TRANSACTION", (err: unknown) => {
496	                if (err) { reject(err); } else { resolve(); }
497	            });
498	        });
499	
500	        // Use query().stream() for row-by-row streaming
501	        const query = connection.query(sql, params);
502	        const stream = query.stream();
503	
504	        await new Promise<void>((resolve, reject) => {
505	            const batch: Record<string, unknown>[] = [];
506	
507	            const flush = async () => {
508	                if (0 < batch.length) {
509	                    const rows = [...batch];
510	                    batch.length = 0;
511	                    await onBatch(rows);
512	                }
513	            };
514	
515	            stream.on("data", (row: Record<string, unknown>) => {
516	                batch.push(row);
517	                if (STREAM_BATCH_SIZE === batch.length) {
518	                    const rows = [...batch];
519	                    batch.length = 0;
520	                    void onBatch(rows);
521	                }
522	            });
523	            stream.on("end", async () => {
524	                try {
525	                    await flush();
526	                    resolve();
527	                } catch (error: unknown) {
528	                    reject(error);
529	                }
530	            });
531	            stream.on("error", (error: unknown) => {
532	                reject(error);
533	            });
534	        });
535	
536	        await new Promise<void>((resolve, reject) => {
537	            connection.query("COMMIT", (err: unknown) => {
538	                if (err) { reject(err); } else { resolve(); }
539	            });
540	        });
541	    } catch (error) {
542	        try {
543	            connection.query("ROLLBACK", () => {});
544	        } catch {/* ignore rollback error */}
545	        if (error instanceof Error && error.message.includes("Connection destroyed")) {
546	            throw new Error(`MySQL query timed out after ${timeoutMs}ms`);
547	        }
548	        throw error;
549	    } finally {
550	        clearTimeout(timeoutId);
551	        connection.destroy();
552	    }
553	}
